"""A readable parser for standard 5-field cron expressions.

Turns an expression such as ``"30 8 * * 1,3,5"`` into a structured
:class:`CronSchedule` and a human-readable sentence via
:meth:`CronSchedule.describe`.

The design is intentionally top-down:

1.  :func:`parse`            -- the public entry point.
2.  field-parsing helpers    -- one shared :func:`parse_field` dispatcher.
3.  :class:`CronSchedule`    -- the structured result plus :meth:`describe`.
4.  small naming/formatting helpers used by the description.
"""

from __future__ import annotations

from dataclasses import dataclass
from enum import Enum, auto
from typing import Callable

# --------------------------------------------------------------------------- #
# Field metadata
# --------------------------------------------------------------------------- #


class CronError(ValueError):
    """Raised when a cron expression is malformed or out of range."""


@dataclass(frozen=True)
class FieldSpec:
    """The valid bounds and display name of a single cron field."""

    name: str
    min_value: int
    max_value: int


MINUTE = FieldSpec("minute", 0, 59)
HOUR = FieldSpec("hour", 0, 23)
DAY_OF_MONTH = FieldSpec("day of month", 1, 31)
MONTH = FieldSpec("month", 1, 12)
DAY_OF_WEEK = FieldSpec("day of week", 0, 6)

# The five fields, in the order they appear in a cron expression.
FIELD_SPECS: tuple[FieldSpec, ...] = (MINUTE, HOUR, DAY_OF_MONTH, MONTH, DAY_OF_WEEK)


class FieldKind(Enum):
    """How a single field was written, which drives its description."""

    ANY = auto()     # "*"
    SINGLE = auto()  # "42"
    RANGE = auto()   # "1-5"
    LIST = auto()    # "1,3,5"
    STEP = auto()    # "*/15" or "1-30/5"


@dataclass(frozen=True)
class Field:
    """One parsed field: how it was written and every value it matches."""

    kind: FieldKind
    values: tuple[int, ...]   # concrete matching values, sorted ascending
    step: int | None = None   # step size, only set for STEP fields

    @property
    def is_any(self) -> bool:
        return self.kind is FieldKind.ANY

    @property
    def is_single(self) -> bool:
        return self.kind is FieldKind.SINGLE

    @property
    def first(self) -> int:
        return self.values[0]

    @property
    def last(self) -> int:
        return self.values[-1]


# --------------------------------------------------------------------------- #
# Public entry point
# --------------------------------------------------------------------------- #


def parse(expression: str) -> "CronSchedule":
    """Parse a 5-field cron expression into a :class:`CronSchedule`."""
    tokens = _split_into_fields(expression)
    minute, hour, day_of_month, month, day_of_week = (
        parse_field(token, spec) for token, spec in zip(tokens, FIELD_SPECS)
    )
    return CronSchedule(
        expression=expression.strip(),
        minute=minute,
        hour=hour,
        day_of_month=day_of_month,
        month=month,
        day_of_week=day_of_week,
    )


def _split_into_fields(expression: str) -> list[str]:
    """Split on whitespace and confirm exactly five fields are present."""
    tokens = expression.split()
    if len(tokens) != 5:
        raise CronError(f"Expected 5 fields, got {len(tokens)}: {expression!r}")
    return tokens


# --------------------------------------------------------------------------- #
# Field parsing -- one shared dispatcher, one helper per syntax form
# --------------------------------------------------------------------------- #


def parse_field(token: str, spec: FieldSpec) -> Field:
    """Parse a single field, dispatching on its syntax form.

    The order matters: a list may contain ranges or steps, so it is
    detected first and each element is parsed recursively.
    """
    if token == "*":
        return _parse_wildcard(spec)
    if "," in token:
        return _parse_list(token, spec)
    if "/" in token:
        return _parse_step(token, spec)
    if "-" in token:
        return _parse_range(token, spec)
    return _parse_single(token, spec)


def _parse_wildcard(spec: FieldSpec) -> Field:
    return Field(FieldKind.ANY, _full_range(spec))


def _parse_single(token: str, spec: FieldSpec) -> Field:
    return Field(FieldKind.SINGLE, (_parse_value(token, spec),))


def _parse_range(token: str, spec: FieldSpec) -> Field:
    start, end = _parse_bounds(token, spec)
    return Field(FieldKind.RANGE, tuple(range(start, end + 1)))


def _parse_list(token: str, spec: FieldSpec) -> Field:
    values: set[int] = set()
    for element in token.split(","):
        if not element:
            raise CronError(f"{spec.name}: empty element in list {token!r}")
        values.update(parse_field(element, spec).values)
    return Field(FieldKind.LIST, tuple(sorted(values)))


def _parse_step(token: str, spec: FieldSpec) -> Field:
    base, _, step_text = token.partition("/")
    step = _parse_step_size(step_text, spec)
    start, end = _step_bounds(base, spec)
    return Field(FieldKind.STEP, tuple(range(start, end + 1, step)), step=step)


# --------------------------------------------------------------------------- #
# Low-level value/range/step parsing
# --------------------------------------------------------------------------- #


def _full_range(spec: FieldSpec) -> tuple[int, ...]:
    return tuple(range(spec.min_value, spec.max_value + 1))


def _parse_value(token: str, spec: FieldSpec) -> int:
    """Parse a single integer and confirm it is within the field's bounds."""
    try:
        value = int(token)
    except ValueError:
        raise CronError(f"{spec.name}: {token!r} is not an integer") from None
    if not (spec.min_value <= value <= spec.max_value):
        raise CronError(
            f"{spec.name}: {value} is out of range "
            f"{spec.min_value}-{spec.max_value}"
        )
    return value


def _parse_bounds(token: str, spec: FieldSpec) -> tuple[int, int]:
    """Parse an ``"a-b"`` range into validated, ordered (start, end)."""
    parts = token.split("-")
    if len(parts) != 2:
        raise CronError(f"{spec.name}: {token!r} is not a valid range")
    start, end = _parse_value(parts[0], spec), _parse_value(parts[1], spec)
    if start > end:
        raise CronError(f"{spec.name}: range start {start} is after end {end}")
    return start, end


def _step_bounds(base: str, spec: FieldSpec) -> tuple[int, int]:
    """Resolve the range a step iterates over (the part before the '/')."""
    if base == "*":
        return spec.min_value, spec.max_value
    if "-" in base:
        return _parse_bounds(base, spec)
    return _parse_value(base, spec), spec.max_value


def _parse_step_size(step_text: str, spec: FieldSpec) -> int:
    try:
        step = int(step_text)
    except ValueError:
        raise CronError(f"{spec.name}: step {step_text!r} is not an integer") from None
    if step <= 0:
        raise CronError(f"{spec.name}: step must be positive, got {step}")
    return step


# --------------------------------------------------------------------------- #
# Structured result + human-readable description
# --------------------------------------------------------------------------- #


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression."""

    expression: str
    minute: Field
    hour: Field
    day_of_month: Field
    month: Field
    day_of_week: Field

    def describe(self) -> str:
        """Render the schedule as a human-readable English sentence."""
        time_phrase = self._describe_time()
        calendar_phrase = self._describe_calendar()
        if calendar_phrase:
            return f"{time_phrase} {calendar_phrase}"
        return time_phrase

    # -- time of day ------------------------------------------------------- #

    def _describe_time(self) -> str:
        minute, hour = self.minute, self.hour

        # "Every minute" / "Every 15 minutes"
        if minute.is_any and hour.is_any:
            return "Every minute"
        if minute.kind is FieldKind.STEP and hour.is_any:
            return _every_n("minute", minute.step)

        # "Every 2 hours, on the hour"
        if hour.kind is FieldKind.STEP and _matches_only_zero(minute):
            return f"{_every_n('hour', hour.step)}, on the hour"

        # A specific clock time: "At 08:30", "At midnight"
        if minute.is_single and hour.is_single:
            return f"At {_clock(hour.first, minute.first)}"

        # General fallback that still reads as English.
        minutes = _list_phrase(minute, str)
        hours = "every hour" if hour.is_any else f"hour {_list_phrase(hour, str)}"
        unit = "minute" if minute.is_single else "minutes"
        return f"At {minutes} {unit} past {hours}"

    # -- calendar (day of month / month / day of week) -------------------- #

    def _describe_calendar(self) -> str:
        clauses: list[str] = []

        if not self.day_of_month.is_any:
            clauses.append(self._describe_day_of_month())
        elif not self.month.is_any:
            clauses.append(f"in {_list_phrase(self.month, _month_name)}")

        if not self.day_of_week.is_any:
            clauses.append(f"on {_list_phrase(self.day_of_week, _weekday_name)}")

        return " ".join(clauses)

    def _describe_day_of_month(self) -> str:
        days = _list_phrase(self.day_of_month, _ordinal)
        if self.month.is_any:
            return f"on the {days} of every month"
        return f"on the {days} of {_list_phrase(self.month, _month_name)}"


# --------------------------------------------------------------------------- #
# Naming + formatting helpers
# --------------------------------------------------------------------------- #

WEEKDAY_NAMES: tuple[str, ...] = (
    "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday",
)

MONTH_NAMES: tuple[str, ...] = (
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
)


def _weekday_name(value: int) -> str:
    return WEEKDAY_NAMES[value]


def _month_name(value: int) -> str:
    return MONTH_NAMES[value - 1]


def _ordinal(value: int) -> str:
    """Format an integer as an English ordinal: 1 -> '1st', 22 -> '22nd'."""
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")
    return f"{value}{suffix}"


def _every_n(unit: str, n: int | None) -> str:
    """'Every minute' for a step of 1, otherwise 'Every N <unit>s'."""
    if n is None or n == 1:
        return f"Every {unit}"
    return f"Every {n} {unit}s"


def _clock(hour: int, minute: int) -> str:
    if hour == 0 and minute == 0:
        return "midnight"
    return f"{hour:02d}:{minute:02d}"


def _matches_only_zero(field: Field) -> bool:
    return field.is_single and field.first == 0


def _list_phrase(field: Field, name: Callable[[int], str]) -> str:
    """Render a field's values: 'Monday through Friday', 'A, B, and C'."""
    if field.kind is FieldKind.RANGE:
        return f"{name(field.first)} through {name(field.last)}"
    return _oxford_join([name(value) for value in field.values])


def _oxford_join(items: list[str]) -> str:
    """Join with an Oxford comma: ['a','b','c'] -> 'a, b, and c'."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


# --------------------------------------------------------------------------- #
# Demo
# --------------------------------------------------------------------------- #

if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for example in examples:
        print(f"{example:<16} -> {parse(example).describe()}")
```

### How it's decomposed

- **`parse`** — the only public entry point; reads top-to-bottom.
- **`parse_field`** — one shared dispatcher used for all 5 fields (and recursively for list elements), so the `*` / range / list / step / single logic lives in exactly one place.
- **Syntax helpers** (`_parse_wildcard`, `_parse_range`, `_parse_list`, `_parse_step`, `_parse_single`) — each handles one form and nothing else.
- **Low-level validators** (`_parse_value`, `_parse_bounds`, `_step_bounds`, `_parse_step_size`) — all bounds-checking and clear `CronError` messages funnel through these.
- **`CronSchedule`** — a frozen dataclass (structured result, not a dict) whose `describe()` splits into `_describe_time` and `_describe_calendar`.
- **Naming/formatting helpers** (`_ordinal`, `_weekday_name`, `_oxford_join`, `_list_phrase`, etc.) — small, single-purpose, and reused across every field's description.

Each function carries full type hints, and `FieldKind` is preserved on each `Field` specifically so the description layer can phrase ranges (`through`), lists (Oxford comma), and steps (`Every N`) correctly without re-parsing.

