```python
"""
cron_parser.py
==============
Standard 5-field cron expression parser with human-readable descriptions.

Format:  minute  hour  day_of_month  month  day_of_week

Supported per-field syntax
  *        every value in the field's allowed range
  N        a single value
  N-M      every value from N to M, inclusive
  */S      every S-th value across the full range
  N-M/S    every S-th value from N to M
  A,B,...  comma-separated combination of any of the above

Field ranges
  minute:       0–59      hour:  0–23
  day_of_month: 1–31     month:  1–12
  day_of_week:  0–6  (0 = Sunday)

Quick start
  >>> schedule = parse("30 8 * * 1,3,5")
  >>> schedule.describe()
  'At 08:30 on Monday, Wednesday, and Friday'
  >>> schedule.minute.values
  [30]
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import NamedTuple


# ── Field metadata ─────────────────────────────────────────────────────────────
#
# All five fields share the same parsing logic; only these bounds differ.


class FieldMeta(NamedTuple):
    """Name and inclusive numeric bounds for one of the five cron fields."""

    name: str
    min_value: int
    max_value: int


FIELDS: list[FieldMeta] = [
    FieldMeta("minute",       0,  59),
    FieldMeta("hour",         0,  23),
    FieldMeta("day_of_month", 1,  31),
    FieldMeta("month",        1,  12),
    FieldMeta("day_of_week",  0,   6),
]


# ── Segment class hierarchy ────────────────────────────────────────────────────
#
# A "segment" is one comma-separated token inside a field, e.g.:
#   "1,5-10,*/15"  →  [ValueSegment(1), RangeSegment(5,10), StepSegment(0,59,15)]
#
# Each subclass carries only the attributes relevant to its form, so readers
# never have to ask "what does None mean here?"


class Segment(ABC):
    """One comma-separated element within a cron field."""

    @abstractmethod
    def expand(self) -> tuple[int, ...]:
        """Return every integer value matched by this segment."""
        ...


@dataclass(frozen=True)
class WildcardSegment(Segment):
    """Matches every value across the field's full allowed range:  *"""

    min_value: int
    max_value: int

    def expand(self) -> tuple[int, ...]:
        return tuple(range(self.min_value, self.max_value + 1))


@dataclass(frozen=True)
class ValueSegment(Segment):
    """Matches exactly one integer:  N"""

    value: int

    def expand(self) -> tuple[int, ...]:
        return (self.value,)


@dataclass(frozen=True)
class RangeSegment(Segment):
    """Matches every integer from start to end, inclusive:  N-M"""

    start: int
    end: int

    def expand(self) -> tuple[int, ...]:
        return tuple(range(self.start, self.end + 1))


@dataclass(frozen=True)
class StepSegment(Segment):
    """Matches every S-th value within [start, end]:  */S  or  N-M/S

    ``is_full_range`` is True when the base was * (vs an explicit N-M range).
    """

    start: int
    end: int
    step: int
    is_full_range: bool

    def expand(self) -> tuple[int, ...]:
        return tuple(range(self.start, self.end + 1, self.step))


# ── ParsedField ────────────────────────────────────────────────────────────────


@dataclass
class ParsedField:
    """One fully-parsed cron field, split into its constituent segments."""

    name: str
    raw: str                  # original text as written, e.g. "1,5-10"
    segments: list[Segment]

    @property
    def values(self) -> list[int]:
        """All integers matched by this field, sorted and deduplicated."""
        seen: set[int] = set()
        result: list[int] = []
        for seg in self.segments:
            for value in seg.expand():
                if value not in seen:
                    seen.add(value)
                    result.append(value)
        return sorted(result)

    @property
    def is_wildcard(self) -> bool:
        """True only for a bare wildcard (*)."""
        return len(self.segments) == 1 and isinstance(self.segments[0], WildcardSegment)

    @property
    def is_single_step(self) -> bool:
        """True when the field is a single step expression, e.g. */15."""
        return len(self.segments) == 1 and isinstance(self.segments[0], StepSegment)

    @property
    def is_single_value(self) -> bool:
        """True when the field resolves to exactly one concrete integer."""
        return len(self.values) == 1


# ── CronSchedule ──────────────────────────────────────────────────────────────


@dataclass
class CronSchedule:
    """A fully-parsed 5-field cron expression.

    Each field exposes its matched values as a sorted integer list; the
    schedule as a whole renders itself as an English description.
    """

    raw: str
    minute:       ParsedField
    hour:         ParsedField
    day_of_month: ParsedField
    month:        ParsedField
    day_of_week:  ParsedField

    def describe(self) -> str:
        """Return a human-readable English description of this schedule."""
        return _build_description(self)

    def __str__(self) -> str:
        return self.raw

    def __repr__(self) -> str:
        return f"CronSchedule({self.raw!r})"


# ── Public entry point ─────────────────────────────────────────────────────────


def parse(expression: str) -> CronSchedule:
    """Parse a standard 5-field cron expression into a CronSchedule.

    Raises:
        ValueError: if the expression has the wrong field count, contains
                    invalid syntax, or uses out-of-range values.

    Examples:
        >>> parse("* * * * *").describe()
        'Every minute'
        >>> parse("0 9 * * 1-5").describe()
        'At 09:00 on Monday through Friday'
    """
    raw_fields = _split_expression(expression)
    parsed_fields = [_parse_field(raw, meta) for raw, meta in zip(raw_fields, FIELDS)]

    return CronSchedule(
        raw=expression,
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
    )


# ── Step 1: split the raw string into field tokens ────────────────────────────


def _split_expression(expression: str) -> list[str]:
    """Split and validate that the expression contains exactly 5 fields."""
    if not expression or not expression.strip():
        raise ValueError("Cron expression cannot be empty")

    fields = expression.strip().split()
    if len(fields) != 5:
        raise ValueError(
            f"Expected 5 fields, got {len(fields)} in expression: {expression!r}"
        )
    return fields


# ── Step 2: parse each field string into segments ─────────────────────────────


def _parse_field(raw: str, meta: FieldMeta) -> ParsedField:
    """Parse one cron field string (e.g. '1,5-10,*/15') into a ParsedField.

    Splits on commas first, then delegates each token to _parse_segment.
    This single function is shared by all five cron fields.
    """
    tokens = [t.strip() for t in raw.split(",")]
    segments = [_parse_segment(token, meta) for token in tokens]
    return ParsedField(name=meta.name, raw=raw, segments=segments)


def _parse_segment(token: str, meta: FieldMeta) -> Segment:
    """Parse one comma-separated token into the appropriate Segment subclass.

    Dispatch order — checked left-to-right, first match wins:
      1. Contains '/'  →  step  (*/N  or  N-M/S)
      2. Contains '-'  →  range  (N-M)
      3. Equals  '*'   →  wildcard
      4. Otherwise     →  single value
    """
    if "/" in token:
        return _parse_step(token, meta)
    if "-" in token:
        return _parse_range(token, meta)
    if token == "*":
        return WildcardSegment(min_value=meta.min_value, max_value=meta.max_value)
    return _parse_value(token, meta)


def _parse_step(token: str, meta: FieldMeta) -> StepSegment:
    """Parse */S or N-M/S into a StepSegment.

    The base may be:
      *    → full range (field min to field max)
      N-M  → explicit sub-range
      N    → from N to field max  (less common but valid)
    """
    base_text, step_text = token.split("/", maxsplit=1)
    step = _require_positive_int(step_text, field=meta.name, context=f"step in '{token}'")

    if base_text == "*":
        return StepSegment(
            start=meta.min_value, end=meta.max_value,
            step=step, is_full_range=True,
        )

    if "-" in base_text:
        start, end = _parse_range_bounds(base_text, meta)
        return StepSegment(start=start, end=end, step=step, is_full_range=False)

    # N/S  →  from N to field maximum, stepping by S
    start = _require_int(base_text, field=meta.name, context=f"step base in '{token}'")
    _require_in_range(start, meta)
    return StepSegment(start=start, end=meta.max_value, step=step, is_full_range=False)


def _parse_range(token: str, meta: FieldMeta) -> RangeSegment:
    """Parse N-M into a RangeSegment."""
    start, end = _parse_range_bounds(token, meta)
    return RangeSegment(start=start, end=end)


def _parse_value(token: str, meta: FieldMeta) -> ValueSegment:
    """Parse a single integer token into a ValueSegment."""
    value = _require_int(token, field=meta.name)
    _require_in_range(value, meta)
    return ValueSegment(value=value)


def _parse_range_bounds(token: str, meta: FieldMeta) -> tuple[int, int]:
    """Parse 'N-M' into (N, M) with ordering and range validation.

    Shared by _parse_range() and _parse_step() for explicit base ranges.
    """
    parts = token.split("-", maxsplit=1)
    if len(parts) != 2:
        raise ValueError(f"Invalid range {token!r} in field '{meta.name}'")

    start = _require_int(parts[0], field=meta.name, context=f"range start in '{token}'")
    end   = _require_int(parts[1], field=meta.name, context=f"range end in '{token}'")

    if start > end:
        raise ValueError(
            f"Range start ({start}) must not exceed end ({end}) "
            f"in field '{meta.name}'"
        )
    _require_in_range(start, meta)
    _require_in_range(end, meta)
    return start, end


# ── Validation utilities ───────────────────────────────────────────────────────


def _require_int(text: str, *, field: str, context: str = "") -> int:
    """Parse text as an integer, raising a descriptive error if it's non-numeric."""
    try:
        return int(text.strip())
    except ValueError:
        location = f" ({context})" if context else ""
        raise ValueError(f"Expected an integer in field '{field}'{location}, got {text!r}")


def _require_positive_int(text: str, *, field: str, context: str = "") -> int:
    """Parse text as a positive (> 0) integer."""
    value = _require_int(text, field=field, context=context)
    if value <= 0:
        raise ValueError(
            f"Step must be a positive integer in field '{field}', got {value}"
        )
    return value


def _require_in_range(value: int, meta: FieldMeta) -> None:
    """Raise ValueError if value falls outside the allowed range for this field."""
    if not (meta.min_value <= value <= meta.max_value):
        raise ValueError(
            f"Value {value} is out of the allowed range "
            f"[{meta.min_value}–{meta.max_value}] for field '{meta.name}'"
        )


# ── Description generation ─────────────────────────────────────────────────────
#
# Builds a human-readable English sentence from the five parsed fields.
# Structure:  <time clause>  [on <days>]  [on the <dom>]  [in <months>]

DAY_NAMES: list[str] = [
    "Sunday", "Monday", "Tuesday", "Wednesday",
    "Thursday", "Friday", "Saturday",
]

MONTH_NAMES: list[str] = [
    "",  # placeholder — months are 1-indexed, so index 0 is unused
    "January", "February", "March",     "April",    "May",      "June",
    "July",    "August",   "September", "October",  "November", "December",
]


def _build_description(schedule: CronSchedule) -> str:
    """Assemble the full English description from all five fields.

    Collects an optional clause from each constraint field (day-of-week,
    day-of-month, month) and joins them after the mandatory time clause.
    """
    if _all_wildcards(schedule):
        return "Every minute"

    parts: list[str] = [_describe_time(schedule.minute, schedule.hour)]

    for clause in [
        _describe_day_of_week(schedule.day_of_week),
        _describe_day_of_month(schedule.day_of_month),
        _describe_month(schedule.month),
    ]:
        if clause:
            parts.append(clause)

    return " ".join(parts)


def _all_wildcards(schedule: CronSchedule) -> bool:
    """Return True only when every field is a bare wildcard (the '* * * * *' case)."""
    return all(
        field.is_wildcard
        for field in (
            schedule.minute, schedule.hour, schedule.day_of_month,
            schedule.month, schedule.day_of_week,
        )
    )


# ── Time clause (minute + hour) ────────────────────────────────────────────────


def _describe_time(minute: ParsedField, hour: ParsedField) -> str:
    """Build the time-of-day portion of the description.

    Recognises these common patterns before falling back to a generic form:

      Pattern                  Example input    Output
      ──────────────────────────────────────────────────────────────────
      every N minutes          */15  *          "Every 15 minutes"
      every N hours            *     */3        "Every 3 hours"
      every N hours, on hour   0     */2        "Every 2 hours, on the hour"
      specific clock time      30    8          "At 08:30"  (or "At midnight")
    """
    if minute.is_single_step and hour.is_wildcard:
        n = _step_of(minute)
        return f"Every {n} {_plural('minute', n)}"

    if hour.is_single_step and minute.is_wildcard:
        n = _step_of(hour)
        return f"Every {n} {_plural('hour', n)}"

    if hour.is_single_step and minute.values == [0]:
        n = _step_of(hour)
        return f"Every {n} {_plural('hour', n)}, on the hour"

    if minute.is_single_value and hour.is_single_value:
        return f"At {_format_clock_time(hour.values[0], minute.values[0])}"

    return _describe_time_generically(minute, hour)


def _describe_time_generically(minute: ParsedField, hour: ParsedField) -> str:
    """Describe a time pattern that does not match any named shorthand."""
    clauses: list[str] = []
    if not hour.is_wildcard:
        clauses.append(f"at hour {_oxford_join([str(v) for v in hour.values])}")
    if not minute.is_wildcard:
        clauses.append(f"at minute {_oxford_join([str(v) for v in minute.values])}")
    return " ".join(clauses) if clauses else "every minute"


def _format_clock_time(hour: int, minute: int) -> str:
    """Format a specific hour and minute as a readable English clock string."""
    if hour == 0 and minute == 0:
        return "midnight"
    if hour == 12 and minute == 0:
        return "noon"
    return f"{hour:02d}:{minute:02d}"


# ── Day-of-week clause ─────────────────────────────────────────────────────────


def _describe_day_of_week(dow: ParsedField) -> str:
    """Return 'on {days}' describing the day-of-week constraint, or '' if unrestricted."""
    if dow.is_wildcard:
        return ""

    sole = dow.segments[0] if len(dow.segments) == 1 else None

    if isinstance(sole, RangeSegment):
        return f"on {DAY_NAMES[sole.start]} through {DAY_NAMES[sole.end]}"

    if isinstance(sole, StepSegment):
        n = sole.step
        return f"every {n} {_plural('day', n)}"

    # Single value or comma-separated list: name each matched day
    return f"on {_oxford_join([DAY_NAMES[v] for v in dow.values])}"


# ── Day-of-month clause ────────────────────────────────────────────────────────


def _describe_day_of_month(dom: ParsedField) -> str:
    """Return 'on the {N}th of every month' or '' if unrestricted."""
    if dom.is_wildcard:
        return ""

    ordinals = [_ordinal(v) for v in dom.values]
    return f"on the {_oxford_join(ordinals)} of every month"


# ── Month clause ───────────────────────────────────────────────────────────────


def _describe_month(month: ParsedField) -> str:
    """Return 'in {months}' or '' if unrestricted."""
    if month.is_wildcard:
        return ""

    sole = month.segments[0] if len(month.segments) == 1 else None

    if isinstance(sole, RangeSegment):
        return f"in {MONTH_NAMES[sole.start]} through {MONTH_NAMES[sole.end]}"

    return f"in {_oxford_join([MONTH_NAMES[v] for v in month.values])}"


# ── Formatting utilities ───────────────────────────────────────────────────────


def _step_of(field: ParsedField) -> int:
    """Extract the step integer from a field that contains a single StepSegment."""
    seg = field.segments[0]
    assert isinstance(seg, StepSegment), f"Expected StepSegment, got {type(seg).__name__}"
    return seg.step


def _plural(word: str, count: int) -> str:
    """Append 's' when count != 1:  _plural('minute', 1) → 'minute'."""
    return word if count == 1 else f"{word}s"


def _ordinal(n: int) -> str:
    """Convert an integer to its English ordinal:  1 → '1st',  12 → '12th',  21 → '21st'."""
    # 11, 12, 13 are irregular — they take 'th', not 'st'/'nd'/'rd'
    if 11 <= (n % 100) <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
    return f"{n}{suffix}"


def _oxford_join(items: list[str]) -> str:
    """Join strings with commas and a final Oxford 'and'.

    ['a']          → 'a'
    ['a', 'b']     → 'a and b'
    ['a', 'b', 'c']→ 'a, b, and c'
    """
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return f"{', '.join(items[:-1])}, and {items[-1]}"


