from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


@dataclass(frozen=True)
class CronFieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class ParsedField:
    spec: CronFieldSpec
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.spec.minimum, self.spec.maximum + 1))

    @property
    def single_value(self) -> int | None:
        return self.values[0] if len(self.values) == 1 else None


@dataclass(frozen=True)
class CronSchedule:
    minute: ParsedField
    hour: ParsedField
    day_of_month: ParsedField
    month: ParsedField
    day_of_week: ParsedField

    @classmethod
    def parse(cls, expression: str) -> CronSchedule:
        parts = expression.split()

        if len(parts) != 5:
            raise ValueError(
                f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
            )

        return cls(
            minute=parse_field(parts[0], MINUTE),
            hour=parse_field(parts[1], HOUR),
            day_of_month=parse_field(parts[2], DAY_OF_MONTH),
            month=parse_field(parts[3], MONTH),
            day_of_week=parse_field(parts[4], DAY_OF_WEEK),
        )

    def describe(self) -> str:
        if self._is_every_minute():
            return "Every minute"

        if self._is_every_n_minutes():
            step = detect_uniform_step(self.minute.values)
            return f"Every {step} minutes"

        if self._is_every_n_hours_on_the_hour():
            step = detect_uniform_step(self.hour.values)
            return f"Every {step} hours, on the hour"

        time_text = describe_time(self.hour, self.minute)
        date_parts = describe_date_parts(
            self.day_of_month,
            self.month,
            self.day_of_week,
        )

        if not date_parts:
            return time_text

        return f"{time_text} {', '.join(date_parts)}"

    def _is_every_minute(self) -> bool:
        return (
            self.minute.is_wildcard
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _is_every_n_minutes(self) -> bool:
        return (
            self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
            and starts_at_minimum_with_uniform_step(self.minute)
        )

    def _is_every_n_hours_on_the_hour(self) -> bool:
        return (
            self.minute.single_value == 0
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
            and starts_at_minimum_with_uniform_step(self.hour)
        )


MINUTE = CronFieldSpec("minute", 0, 59)
HOUR = CronFieldSpec("hour", 0, 23)
DAY_OF_MONTH = CronFieldSpec("day_of_month", 1, 31)
MONTH = CronFieldSpec("month", 1, 12)
DAY_OF_WEEK = CronFieldSpec("day_of_week", 0, 6)

WEEKDAY_NAMES = {
    0: "Sunday",
    1: "Monday",
    2: "Tuesday",
    3: "Wednesday",
    4: "Thursday",
    5: "Friday",
    6: "Saturday",
}

MONTH_NAMES = {
    1: "January",
    2: "February",
    3: "March",
    4: "April",
    5: "May",
    6: "June",
    7: "July",
    8: "August",
    9: "September",
    10: "October",
    11: "November",
    12: "December",
}


def parse_cron(expression: str) -> CronSchedule:
    return CronSchedule.parse(expression)


def parse_field(raw: str, spec: CronFieldSpec) -> ParsedField:
    if not raw:
        raise ValueError(f"{spec.name} field cannot be empty")

    values: set[int] = set()

    for part in raw.split(","):
        if not part:
            raise ValueError(f"Empty list item in {spec.name} field: {raw!r}")

        values.update(parse_field_part(part, spec))

    return ParsedField(spec=spec, values=tuple(sorted(values)))


def parse_field_part(part: str, spec: CronFieldSpec) -> set[int]:
    base, step = split_step(part, spec)
    base_values = parse_base(base, spec)

    if step is None:
        return base_values

    return apply_step(base_values, step)


def split_step(part: str, spec: CronFieldSpec) -> tuple[str, int | None]:
    pieces = part.split("/")

    if len(pieces) == 1:
        return part, None

    if len(pieces) != 2:
        raise ValueError(f"Invalid step syntax in {spec.name} field: {part!r}")

    base, step_text = pieces

    if not base:
        raise ValueError(f"Missing step base in {spec.name} field: {part!r}")

    if not step_text.isdigit():
        raise ValueError(f"Invalid step value in {spec.name} field: {part!r}")

    step = int(step_text)

    if step <= 0:
        raise ValueError(f"Step must be greater than zero in {spec.name} field")

    return base, step


def parse_base(base: str, spec: CronFieldSpec) -> set[int]:
    if base == "*":
        return set(range(spec.minimum, spec.maximum + 1))

    if "-" in base:
        return parse_range(base, spec)

    return {parse_single_value(base, spec)}


def parse_range(raw_range: str, spec: CronFieldSpec) -> set[int]:
    pieces = raw_range.split("-")

    if len(pieces) != 2:
        raise ValueError(f"Invalid range in {spec.name} field: {raw_range!r}")

    start = parse_single_value(pieces[0], spec)
    end = parse_single_value(pieces[1], spec)

    if start > end:
        raise ValueError(
            f"Range start cannot be greater than range end in {spec.name} field: "
            f"{raw_range!r}"
        )

    return set(range(start, end + 1))


def parse_single_value(raw_value: str, spec: CronFieldSpec) -> int:
    if not raw_value.isdigit():
        raise ValueError(f"Invalid value in {spec.name} field: {raw_value!r}")

    value = int(raw_value)

    if value < spec.minimum or value > spec.maximum:
        raise ValueError(
            f"{spec.name} value {value} is outside allowed range "
            f"{spec.minimum}-{spec.maximum}"
        )

    return value


def apply_step(values: set[int], step: int) -> set[int]:
    ordered_values = sorted(values)
    first_value = ordered_values[0]

    return {
        value
        for value in ordered_values
        if (value - first_value) % step == 0
    }


def starts_at_minimum_with_uniform_step(field: ParsedField) -> bool:
    if field.is_wildcard or len(field.values) < 2:
        return False

    return field.values[0] == field.spec.minimum and detect_uniform_step(field.values) > 1


def detect_uniform_step(values: Iterable[int]) -> int:
    ordered = tuple(values)

    if len(ordered) < 2:
        return 0

    first_step = ordered[1] - ordered[0]

    if all((right - left) == first_step for left, right in zip(ordered, ordered[1:])):
        return first_step

    return 0


def describe_time(hour: ParsedField, minute: ParsedField) -> str:
    if hour.single_value is None or minute.single_value is None:
        return describe_general_time(hour, minute)

    hour_value = hour.single_value
    minute_value = minute.single_value

    if hour_value == 0 and minute_value == 0:
        return "At midnight"

    return f"At {hour_value:02d}:{minute_value:02d}"


def describe_general_time(hour: ParsedField, minute: ParsedField) -> str:
    if hour.is_wildcard and minute.single_value == 0:
        return "Every hour, on the hour"

    if hour.is_wildcard and minute.single_value is not None:
        return f"At {minute.single_value} minutes past every hour"

    if minute.is_wildcard and hour.single_value is not None:
        return f"Every minute during hour {hour.single_value:02d}"

    return f"At minutes {format_values(minute.values)} during hours {format_values(hour.values)}"


def describe_date_parts(
    day_of_month: ParsedField,
    month: ParsedField,
    day_of_week: ParsedField,
) -> list[str]:
    parts: list[str] = []

    if not day_of_month.is_wildcard:
        parts.append(describe_day_of_month(day_of_month))

    if not month.is_wildcard:
        parts.append(describe_month(month))

    if not day_of_week.is_wildcard:
        parts.append(describe_day_of_week(day_of_week))

    return parts


def describe_day_of_month(day_of_month: ParsedField) -> str:
    if day_of_month.single_value is not None:
        return f"on the {ordinal(day_of_month.single_value)} of every month"

    return f"on days {format_values(day_of_month.values)} of every month"


def describe_month(month: ParsedField) -> str:
    names = [MONTH_NAMES[value] for value in month.values]

    if month.single_value is not None:
        return f"in {names[0]}"

    return f"in {format_english_list(names)}"


def describe_day_of_week(day_of_week: ParsedField) -> str:
    values = day_of_week.values
    names = [WEEKDAY_NAMES[value] for value in values]

    if is_contiguous(values):
        return f"on {names[0]} through {names[-1]}"

    return f"on {format_english_list(names)}"


def is_contiguous(values: tuple[int, ...]) -> bool:
    return len(values) > 1 and all(
        right == left + 1 for left, right in zip(values, values[1:])
    )


def format_values(values: Iterable[int]) -> str:
    return format_english_list([str(value) for value in values])


def format_english_list(items: list[str]) -> str:
    if not items:
        return ""

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


